artifacts.body:
{
  "@context": "https://schema.org",
  "@type": "Product",
  "name": "[Product name]",
  "brand": {
    "@type": "Brand",
    "name": "Sennen"
  },
  "category": "skincare",
  "description": "[Product description — include the details assistants quote: editorial & press coverage, third-party testing / certification, price & value, awards & recognition].",
  "sku": "[SKU]",
  "offers": {
    "@type": "Offer",
    "price": "[price]",
    "priceCurrency": "[USD]",
    "availability": "https://schema.org/InStock",
    "url": "[product URL]"
  },
  "aggregateRating": {
    "@type": "AggregateRating",
    "ratingValue": "[average rating, only if real]",
    "reviewCount": "[review count, only if real]"
  }
}
